      setTimeout(() => { ws.close(); resolve({ content: [{ type: 'text', text: 'Cancel request sent for run ' + run_id }] }); }, 500);
    });
    ws.on('error', (e) => { clearTimeout(timeout); resolve({ content: [{ type: 'text', text: 'Error: ' + e.message }] }); });
  });
